#include <linux/kernel.h>

void debug_kernel_function(int value)
{
    // Emergency message - system is unusable
    printk(KERN_EMERG "CRITICAL: System failure at %s\n", __FUNCTION__);

    // Alert - immediate action required
    printk(KERN_ALERT "ALERT: Resource exhaustion detected\n");

    // Critical error
    printk(KERN_CRIT "CRITICAL: Kernel panic imminent\n");

    // Error condition
    printk(KERN_ERR "ERROR: Failed to allocate memory\n");

    // Warning
    printk(KERN_WARNING "WARNING: Buffer nearly full\n");

    // Notice (normal but significant)
    printk(KERN_NOTICE "NOTICE: Service started\n");

    // Informational
    printk(KERN_INFO "INFO: Processing %d items\n", value);

    // Debug message
    printk(KERN_DEBUG "DEBUG: Variable value = %d\n", value);
}

