/*
 * DEADLOCK DETECTION USING RESOURCE ALLOCATION GRAPH
 * 
 * A deadlock exists if and only if the resource allocation graph
 * contains a CYCLE where all resources have exactly one instance.
 */

#include <stdio.h>
#include <stdbool.h>

#define MAX_PROCESSES 5
#define MAX_RESOURCES 4

// Global variables
int available[MAX_RESOURCES];
int allocation[MAX_PROCESSES][MAX_RESOURCES];
int request[MAX_PROCESSES][MAX_RESOURCES];

// Check if deadlock exists using banker's-like detection
bool detect_deadlock(int num_processes, int num_resources)
{
    int work[MAX_RESOURCES];
    bool finish[MAX_PROCESSES] = {false};
    int safe_sequence[MAX_PROCESSES];
    int count = 0;

    // Initialize work with available resources
    for (int i = 0; i < num_resources; i++)
        work[i] = available[i];

    // Try to find a safe sequence
    while (count < num_processes)
    {
        bool found = false;

        for (int p = 0; p < num_processes; p++)
        {
            if (!finish[p])
            {
                // Check if all requests can be satisfied
                bool can_proceed = true;
                for (int r = 0; r < num_resources; r++)
                {
                    if (request[p][r] > work[r])
                    {
                        can_proceed = false;
                        break;
                    }
                }

                if (can_proceed)
                {
                    // Simulate releasing resources
                    for (int r = 0; r < num_resources; r++)
                        work[r] += allocation[p][r];

                    finish[p] = true;
                    safe_sequence[count++] = p;
                    found = true;
                }
            }
        }

        // No process could proceed - DEADLOCK EXISTS
        if (!found)
        {
            printf("\n*** DEADLOCK DETECTED! ***\n");
            printf("Deadlocked processes: ");
            for (int p = 0; p < num_processes; p++)
            {
                if (!finish[p])
                    printf("P%d ", p);
            }
            printf("\n");
            return true;
        }
    }

    printf("\nNo deadlock. Safe sequence: ");
    for (int i = 0; i < count; i++)
        printf("P%d ", safe_sequence[i]);
    printf("\n");

    return false;
}

// Main function demonstrating deadlock detection
int main()
{
    int num_processes = 3;
    int num_resources = 2;

    // Available resources
    available[0] = 2; available[1] = 0;

    // Allocation matrix (which resources are held)
    allocation[0][0] = 1; allocation[0][1] = 0;
    allocation[1][0] = 0; allocation[1][1] = 1;
    allocation[2][0] = 0; allocation[2][1] = 0;

    // Request matrix (what processes are requesting)
    request[0][0] = 0; request[0][1] = 1;  // P0 requests R1
    request[1][0] = 1; request[1][1] = 0;  // P1 requests R0
    request[2][0] = 0; request[2][1] = 0;

    printf("Running deadlock detection...\n");
    detect_deadlock(num_processes, num_resources);

    return 0;
}
